    def __init__(self, row, col, is_black=False):
        super().__init__(row, col, is_black)

    def is_valid_move(self, to_row, to_col, board):
        # King can move in any direction diagonally
        if abs(to_row - self.row) == 1 and abs(to_col - self.col) == 1:
            target = board.get_piece(to_row, to_col)
            return not target
        elif abs(to_row - self.row) == 2 and abs(to_col - self.col) == 2:
            mid_row, mid_col = (self.row + to_row) // 2, (self.col + to_col) // 2
            target = board.get_piece(mid_row, mid_col)
            return target and target.is_black != self.is_black
        return False
